const rows = $input.all().map(i => i.json);
if (rows.length === 0) throw new Error('Tidak ada data cashflow di Google Sheets.');

const pemasukan = rows.filter(r => r.Jenis === 'Pemasukan');
const pengeluaran = rows.filter(r => r.Jenis === 'Pengeluaran');
const toNum = (v) => parseFloat(String(v).replace(/[^0-9.-]/g, '')) || 0;

const totalPemasukan = pemasukan.reduce((s, r) => s + toNum(r.Nominal), 0);
const totalPengeluaran = pengeluaran.reduce((s, r) => s + toNum(r.Nominal), 0);
const cashBalance = totalPemasukan - totalPengeluaran;
const cashflowRatio = totalPemasukan > 0 ? ((cashBalance / totalPemasukan) * 100).toFixed(1) : '0';
const statusCashflow = cashBalance >= 0 ? 'POSITIF' : 'NEGATIF';

const pengeluaranPerDivisi = {};
pengeluaran.forEach(r => { pengeluaranPerDivisi[r.Divisi] = (pengeluaranPerDivisi[r.Divisi] || 0) + toNum(r.Nominal); });
const rankingDivisi = Object.entries(pengeluaranPerDivisi).sort((a, b) => b[1] - a[1]).map(([d, t]) => ({ divisi: d, total: t }));

const pemasukanPerDivisi = {};
pemasukan.forEach(r => { pemasukanPerDivisi[r.Divisi] = (pemasukanPerDivisi[r.Divisi] || 0) + toNum(r.Nominal); });

const formatRp = (n) => 'Rp ' + Math.abs(n).toLocaleString('id-ID');
const semuaDivisi = [...new Set(rows.map(r => r.Divisi))].sort();

let tabelDivisi = '| Divisi | Pemasukan | Pengeluaran | Net |\n|--------|-----------|-------------|-----|\n';
semuaDivisi.forEach(div => {
  const masuk = pemasukanPerDivisi[div] || 0;
  const keluar = pengeluaranPerDivisi[div] || 0;
  tabelDivisi += '| ' + div + ' | ' + formatRp(masuk) + ' | ' + formatRp(keluar) + ' | ' + formatRp(masuk - keluar) + ' |\n';
});

let tabelTransaksi = '| Tanggal | Divisi | Jenis | Nominal | Keterangan |\n|---------|--------|-------|---------|------------|\n';
rows.forEach(r => { tabelTransaksi += '| ' + r.Tanggal + ' | ' + r.Divisi + ' | ' + r.Jenis + ' | ' + formatRp(toNum(r.Nominal)) + ' | ' + (r.Keterangan || '-') + ' |\n'; });

const tanggalList = rows.map(r => new Date(r.Tanggal)).filter(d => !isNaN(d.getTime()));
const bulanLaporan = tanggalList.length > 0 ? new Date(Math.max(...tanggalList)).toLocaleDateString('id-ID', { month: 'long', year: 'numeric' }) : 'Terkini';
const tanggalGenerate = new Date().toLocaleDateString('id-ID', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' });

return [{ json: {
  bulanLaporan, tanggalGenerate,
  totalPemasukan, totalPengeluaran, cashBalance, cashflowRatio, statusCashflow,
  jumlahTransaksi: rows.length, jumlahDivisi: semuaDivisi.length,
  divisiTerboros: rankingDivisi[0]?.divisi || 'N/A',
  formatTotalPemasukan: formatRp(totalPemasukan),
  formatTotalPengeluaran: formatRp(totalPengeluaran),
  formatCashBalance: formatRp(Math.abs(cashBalance)),
  formatNominalTerboros: formatRp(rankingDivisi[0]?.total || 0),
  tabelDivisi, tabelTransaksi,
  namaFilePDF: 'Laporan_Cashflow_' + bulanLaporan.replace(/ /g, '_') + '.pdf'
}}];

const laporanNaratif = $input.first().json.output || '';
const dk = $('Proses & Hitung Statistik Keuangan').first().json;

const mdToHtml = (md) => {
  return md
    .replace(/^## (.+)$/gm, '<h2 style="color:#1a3a5c;border-bottom:2px solid #e8edf2;padding-bottom:8px;margin-top:28px">$1</h2>')
    .replace(/^# (.+)$/gm, '<h1 style="color:#1a3a5c">$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/^(\d+)\. (.+)$/gm, '<li style="margin-bottom:8px">$2</li>')
    .replace(/^- (.+)$/gm, '<li style="margin-bottom:6px">$1</li>')
    .replace(/(<li[^>]*>.*?<\/li>\n?)+/gs, m => '<ul style="padding-left:24px;margin:12px 0">' + m + '</ul>')
    .split('\n\n')
    .map(p => p.startsWith('<') ? p : '<p style="margin:10px 0;line-height:1.7">' + p + '</p>')
    .join('\n');
};

const sc = dk.statusCashflow === 'POSITIF' ? '#16a34a' : '#dc2626';
const sb = dk.statusCashflow === 'POSITIF' ? '#dcfce7' : '#fee2e2';

const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:Arial,Helvetica,sans-serif;color:#1f2937;background:#fff}
.wrap{max-width:800px;margin:0 auto;padding:32px}
.hdr{background:linear-gradient(135deg,#1a3a5c 0%,#2c5282 100%);color:white;padding:32px;border-radius:10px;margin-bottom:28px}
.hdr h1{font-size:22px;font-weight:bold;margin-bottom:6px}
.hdr p{font-size:13px;opacity:.85}
.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:28px}
.metric{background:#f8fafc;border-radius:8px;padding:16px;border-top:3px solid #1a3a5c}
.metric .lbl{font-size:10px;text-transform:uppercase;letter-spacing:.5px;color:#6b7280;margin-bottom:6px}
.metric .val{font-size:17px;font-weight:bold;color:#1a3a5c}
.metric.pos .val{color:#16a34a}
.metric.neg .val{color:#dc2626}
.badge{display:inline-block;padding:4px 12px;border-radius:20px;font-size:12px;font-weight:bold;background:${sb};color:${sc};margin-top:4px}
.footer{margin-top:36px;padding-top:18px;border-top:1px solid #e5e7eb;text-align:center;font-size:11px;color:#9ca3af}
</style></head>
<body><div class="wrap">
<div class="hdr">
  <h1>📊 LAPORAN ARUS KAS NARATIF — ${dk.bulanLaporan.toUpperCase()}</h1>
  <p>PT Nusantara Maju &nbsp;|&nbsp; ${dk.tanggalGenerate} &nbsp;|&nbsp; Sistem CFO AI Otomasi</p>
</div>
<div class="metrics">
  <div class="metric pos"><div class="lbl">Total Pemasukan</div><div class="val">${dk.formatTotalPemasukan}</div></div>
  <div class="metric neg"><div class="lbl">Total Pengeluaran</div><div class="val">${dk.formatTotalPengeluaran}</div></div>
  <div class="metric"><div class="lbl">Cash Balance</div><div class="val">${dk.formatCashBalance}</div><div class="badge">${dk.statusCashflow}</div></div>
  <div class="metric"><div class="lbl">Rasio Cashflow</div><div class="val">${dk.cashflowRatio}%</div></div>
</div>
<div class="report">${mdToHtml(laporanNaratif)}</div>
<div class="footer">
  <p>Dibuat otomatis oleh Sistem CFO AI n8n &mdash; ${dk.tanggalGenerate}</p>
  <p style="margin-top:4px">Konfidensial — Hanya untuk internal manajemen PT Nusantara Maju</p>
</div>
</div></body></html>`;

return [{
  json: {
    htmlContent: html,
    laporanNaratif,
    bulanLaporan: dk.bulanLaporan,
    statusCashflow: dk.statusCashflow,
    formatTotalPemasukan: dk.formatTotalPemasukan,
    formatTotalPengeluaran: dk.formatTotalPengeluaran,
    formatCashBalance: dk.formatCashBalance,
    cashflowRatio: dk.cashflowRatio,
    divisiTerboros: dk.divisiTerboros,
    tanggalGenerate: dk.tanggalGenerate,
    namaFilePDF: dk.namaFilePDF
  }
}];
